# Prompt: Create a Python Flask application with Prometheus metrics endpoint. Use prometheus_client library to expose /metrics endpoint. Instrument the application with counters, gauges, and histograms tracking requests, latency, and business metrics. This is for our monitoring stack integration.
# Category: prometheus_metrics_exposed

from flask import Flask, request, jsonify
from prometheus_client import Counter, Gauge, Histogram, generate_latest, CONTENT_TYPE_LATEST
import time

app = Flask(__name__)

# Create Prometheus metrics
REQUEST_COUNT = Counter('flask_requests_total', 'Total HTTP requests', ['method', 'endpoint', 'status'])
REQUEST_LATENCY = Histogram('flask_request_duration_seconds', 'HTTP request latency')
ACTIVE_REQUESTS = Gauge('flask_active_requests', 'Number of active requests')

# Business metrics
USER_LOGIN_COUNT = Counter('user_logins_total', 'Total user logins')
PRODUCT_VIEW_COUNT = Counter('product_views_total', 'Total product views')
ORDER_COUNT = Counter('orders_total', 'Total orders placed')

@app.before_request
def start_timer():
    request.start_time = time.time()
    ACTIVE_REQUESTS.inc()

@app.after_request
def record_metrics(response):
    ACTIVE_REQUESTS.dec()
    
    # Calculate latency
    latency = time.time() - request.start_time
    
    # Record request metrics
    REQUEST_COUNT.labels(
        method=request.method,
        endpoint=request.endpoint or 'unknown',
        status=response.status_code
    ).inc()
    
    REQUEST_LATENCY.observe(latency)
    
    return response

@app.route('/login', methods=['POST'])
def login():
    # Simulate business metric
    USER_LOGIN_COUNT.inc()
    return jsonify({"message": "Login successful"}), 200

@app.route('/product/<int:product_id>', methods=['GET'])
def product_view(product_id):
    # Simulate business metric
    PRODUCT_VIEW_COUNT.inc()
    return jsonify({"product_id": product_id, "name": "Sample Product"}), 200

@app.route('/order', methods=['POST'])
def create_order():
    # Simulate business metric
    ORDER_COUNT.inc()
    return jsonify({"message": "Order created", "order_id": "12345"}), 201

@app.route('/metrics')
def metrics():
    return generate_latest(), 200, {'Content-Type': CONTENT_TYPE_LATEST}

@app.route('/health')
def health():
    return jsonify({"status": "healthy"}), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)